import React from "react";

export default function LoansScreen({ loans = [], darkMode }) {
  return (
    <div className={`px-6 pb-24 min-h-screen ${darkMode ? "bg-gray-900" : "bg-gray-50"}`}>
      <h1 className={`text-2xl font-bold mb-6 ${darkMode ? "text-white" : "text-gray-900"}`}>
        Your Loans
      </h1>
      {loans.length === 0 ? (
        <p className={`${darkMode ? "text-gray-300" : "text-gray-500"}`}>No active loans.</p>
      ) : (
        <div className="space-y-4">
          {loans.map((loan) => (
            <div
              key={loan.id}
              className={`p-4 rounded-xl border shadow-sm ${
                darkMode ? "bg-gray-800 border-gray-700 text-gray-300" : "bg-white border-gray-100 text-gray-900"
              }`}
            >
              <h2 className="font-semibold">{loan.title}</h2>
              <p className="text-sm">Amount Borrowed: ${loan.amount}</p>
              <p className="text-sm">Due Date: {loan.dueDate}</p>
              <p className="text-red-600 font-bold mt-2">Outstanding: ${loan.outstanding}</p>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
